/// {@category Containers}
library;

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/user_accessible_contents_controller.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/paging_data.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/utils/build_context_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/views/components/empty_view.dart';
import 'package:baseball_detector_flutter/views/components/paging_helper.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';
import 'package:baseball_detector_flutter/views/pages/home/players/components/player_card.dart';
import 'package:baseball_detector_flutter/views/pages/home/players/components/player_search_bar_with_filter.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

/// A page widget class to manage player lists.
class PlayersPage extends HookConsumerWidget {
  const PlayersPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final teamId = ref.watch(profileStorageProvider).getTeamId()!;
    final accessibleContents =
        ref.watch(userAccessibleContentsControllerProvider);
    final canAddPlayer = accessibleContents?.hasPrivilegesFor(
          teamId,
          RoleDomain.basic,
          RoleLevel.write,
          false,
        ) ??
        false;

    final keyword = ref.watch(playerSearchKeywordNotifierProvider);

    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: HomePage.bodyPadding,
          child: Column(
            children: [
              // Search bar
              Padding(
                padding: const EdgeInsets.only(bottom: 12),
                child: PlayerSearchBarWithFilter(
                  word: keyword ?? '',
                  onSubmitted: (word) {
                    ref
                        .read(playerSearchKeywordNotifierProvider.notifier)
                        .updateKeyword(
                            word.trim().isEmpty ? null : word.trim());
                  },
                ),
              ),
              // Player list
              Expanded(
                child: PagingHelper<PlayerListController, Player>(
                  provider: playerListControllerProvider,
                  contentBuilder:
                      (PagingData<Player> data, Widget? endItemView) {
                    if (data.items.isEmpty) {
                      return EmptyView(
                        icon: Icons.people_outline,
                        message: keyword != null && keyword.isNotEmpty
                            ? context.l10n.common__no_data
                            : context.l10n.players_page__have_no_data,
                        height: context.screenHeight * 0.8,
                      );
                    }
                    return ListView(
                      children: [
                        ...data.items
                            .map((player) => PlayerCard(player: player)),
                        if (endItemView != null) endItemView else const Gap(80),
                      ],
                    );
                  },
                ),
              ),
            ],
          ),
        ),
      ),
      floatingActionButton: FloatingActionButton(
        backgroundColor: canAddPlayer
            ? null
            : context.isDarkMode
                ? ColorManager.darkSecondaryText
                : ColorManager.secondaryText,
        onPressed: canAddPlayer
            ? () {
                Navigator.of(context).pushNamed(HomeRouter.createPlayerPage);
              }
            : null,
        child: Icon(Icons.person_add_alt),
      ),
    );
  }
}

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/player_list_controller.dart';
import 'package:baseball_detector_flutter/controllers/session_list_controller.dart';
import 'package:baseball_detector_flutter/data/models/failure/failure.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/snack_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_button.dart';
import 'package:baseball_detector_flutter/views/components/custom_loading_indicator.dart';
import 'package:baseball_detector_flutter/views/components/searchable_dropdown_menu.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_team_check.dart';
import 'package:baseball_detector_flutter/views/pages/home/home_page.dart';

class SessionFilterPage extends HookConsumerWidget {
  const SessionFilterPage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final isSingleTeam = useSingleTeamCheck();
    final sessionFilterParameters =
        ref.watch(sessionFilterParametersNotifierProvider);

    final tempPlayer = useState<Player?>(sessionFilterParameters.player);
    final tempLocation = useState<String?>(sessionFilterParameters.location);

    // キーワード検索用コントローラ
    final keywordController = useTextEditingController(
      text: sessionFilterParameters.keyword ?? '',
    );
    final keywordText = useValueListenable(keywordController);

    // 追加: 開始日・終了日用コントローラ
    final startDateController = useTextEditingController(
      text: sessionFilterParameters.startDate != null
          ? "${sessionFilterParameters.startDate!.year.toString().padLeft(4, '0')}-${sessionFilterParameters.startDate!.month.toString().padLeft(2, '0')}-${sessionFilterParameters.startDate!.day.toString().padLeft(2, '0')}"
          : '',
    );
    final endDateController = useTextEditingController(
      text: sessionFilterParameters.endDate != null
          ? "${sessionFilterParameters.endDate!.year.toString().padLeft(4, '0')}-${sessionFilterParameters.endDate!.month.toString().padLeft(2, '0')}-${sessionFilterParameters.endDate!.day.toString().padLeft(2, '0')}"
          : '',
    );
    final startDateText = useValueListenable(startDateController);
    final endDateText = useValueListenable(endDateController);

    // Playerリスト取得
    final allPlayersAsync = ref.watch(allPlayersProvider);
    final playerList = allPlayersAsync.when(
      data: (players) => players,
      loading: () => <Player>[],
      error: (e, _) => <Player>[],
    );

    // Location一覧をAPIから取得
    final sessionLocationsAsync = ref.watch(sessionLocationsProvider);
    final locationList = sessionLocationsAsync.when(
      data: (locations) => locations,
      loading: () => <String>[],
      error: (e, _) => <String>[],
    );

    return Scaffold(
      appBar: CustomAppBar(
        title: context.l10n.session_filter_page__title,
        isBackNavigation: true,
      ),
      body: SafeArea(
        child: allPlayersAsync.when(
          loading: () => const Center(child: CustomLoadingIndicator()),
          error: (error, stack) => Center(
            child: Column(
              mainAxisSize: MainAxisSize.min,
              children: [
                IconButton(
                  onPressed: () {
                    ref.invalidate(sessionLocationsProvider);
                    ref.invalidate(playerListControllerProvider);
                    ref.invalidate(allPlayersProvider);
                  },
                  icon: const Icon(Icons.refresh),
                ),
                Text(context.l10n.get_data_failed),
                const SizedBox(height: 8),
                Text(
                  (error is Failure)
                      ? error.translate(context.l10n)
                      : error.toString(),
                  textAlign: TextAlign.center,
                ),
              ],
            ),
          ),
          data: (_) => Padding(
            padding: HomePage.bodyPadding,
            child: SingleChildScrollView(
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Row(
                    children: [
                      Icon(Icons.search, size: 18),
                      const Gap(4),
                      Text(context.l10n.session_filter_page__keyword),
                    ],
                  ),
                  const Gap(4),
                  SizedBox(
                    height: 48,
                    child: TextField(
                      controller: keywordController,
                      decoration: InputDecoration(
                        hintText: context.l10n.sessions_page__filter_hint,
                        contentPadding: const EdgeInsets.symmetric(
                          vertical: 8,
                          horizontal: 12,
                        ),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(8),
                        ),
                        suffixIcon: keywordText.text.isNotEmpty
                            ? IconButton(
                                icon: Icon(Icons.clear, size: 18),
                                onPressed: () {
                                  keywordController.clear();
                                },
                              )
                            : null,
                      ),
                    ),
                  ),
                  const Gap(16),
                  Row(
                    children: [
                      Icon(Icons.calendar_today, size: 18),
                      const Gap(4),
                      Text(context.l10n.session_filter_page__period),
                    ],
                  ),
                  const Gap(8),
                  Row(
                    children: [
                      // 開始日
                      Expanded(
                        child: SizedBox(
                          height: 48,
                          child: TextField(
                            readOnly: true,
                            controller: startDateController,
                            onTap: () async {
                              final picked = await showDatePicker(
                                context: context,
                                initialDate: startDateController.text.isNotEmpty
                                    ? DateTime.parse(startDateController.text)
                                    : DateTime.now(),
                                firstDate: DateTime(2020),
                                lastDate: DateTime(2100),
                              );
                              if (picked != null) {
                                final str =
                                    "${picked.year.toString().padLeft(4, '0')}-${picked.month.toString().padLeft(2, '0')}-${picked.day.toString().padLeft(2, '0')}";
                                startDateController.text = str;
                              }
                            },
                            decoration: InputDecoration(
                              hintText:
                                  context.l10n.session_filter_page__start_date,
                              contentPadding: const EdgeInsets.symmetric(
                                vertical: 8,
                                horizontal: 12,
                              ),
                              border: OutlineInputBorder(
                                borderRadius: BorderRadius.circular(8),
                              ),
                              suffixIcon: startDateText.text.isNotEmpty
                                  ? IconButton(
                                      icon: Icon(Icons.clear, size: 18),
                                      onPressed: () {
                                        startDateController.clear();
                                      },
                                    )
                                  : null,
                            ),
                          ),
                        ),
                      ),
                      const Gap(12),
                      // 終了日
                      Expanded(
                        child: SizedBox(
                          height: 48,
                          child: TextField(
                            readOnly: true,
                            controller: endDateController,
                            onTap: () async {
                              final picked = await showDatePicker(
                                context: context,
                                initialDate: endDateController.text.isNotEmpty
                                    ? DateTime.parse(endDateController.text)
                                    : DateTime.now(),
                                firstDate: DateTime(1980),
                                lastDate: DateTime(2100),
                              );
                              if (picked != null) {
                                final str =
                                    "${picked.year.toString().padLeft(4, '0')}-${picked.month.toString().padLeft(2, '0')}-${picked.day.toString().padLeft(2, '0')}";
                                endDateController.text = str;
                              }
                            },
                            decoration: InputDecoration(
                              hintText:
                                  context.l10n.session_filter_page__end_date,
                              contentPadding: const EdgeInsets.symmetric(
                                vertical: 8,
                                horizontal: 12,
                              ),
                              border: OutlineInputBorder(
                                borderRadius: BorderRadius.circular(8),
                              ),
                              suffixIcon: endDateText.text.isNotEmpty
                                  ? IconButton(
                                      icon: Icon(Icons.clear, size: 18),
                                      onPressed: () {
                                        endDateController.clear();
                                      },
                                    )
                                  : null,
                            ),
                          ),
                        ),
                      ),
                    ],
                  ),
                  if (!isSingleTeam) ...[
                    const Gap(16),
                    Row(
                      children: [
                        Icon(Icons.person_outline, size: 18),
                        const Gap(4),
                        Text(context.l10n.session_filter_page__player),
                      ],
                    ),
                    const Gap(4),
                    SizedBox(
                      height: 48,
                      child: SearchableDropdownMenu<Player>(
                        value: tempPlayer.value,
                        onChanged: (player) {
                          tempPlayer.value = player;
                        },
                        itemList: playerList,
                        itemBuilder: (p) => Text(p.name ?? ''),
                        displayString: (p) => p.name ?? '',
                        hintText: context.l10n.sessions_page__filter_hint,
                        includeHintTextToList: true,
                        decoration: InputDecoration(
                          contentPadding: const EdgeInsets.symmetric(
                            vertical: 8,
                            horizontal: 12,
                          ),
                          border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(8),
                          ),
                        ),
                      ),
                    ),
                  ],
                  const Gap(16),
                  Row(
                    children: [
                      Icon(Icons.place_outlined, size: 18),
                      const Gap(4),
                      Text(context.l10n.session_filter_page__location),
                    ],
                  ),
                  const Gap(4),
                  SizedBox(
                    height: 48,
                    child: SearchableDropdownMenu<String>(
                      value: tempLocation.value,
                      onChanged: (loc) {
                        tempLocation.value = loc;
                      },
                      itemList: locationList,
                      itemBuilder: (loc) => Text(loc),
                      displayString: (loc) => loc,
                      hintText: context.l10n.sessions_page__filter_hint,
                      includeHintTextToList: true,
                      decoration: InputDecoration(
                        contentPadding: const EdgeInsets.symmetric(
                          vertical: 8,
                          horizontal: 12,
                        ),
                        border: OutlineInputBorder(
                          borderRadius: BorderRadius.circular(8),
                        ),
                      ),
                    ),
                  ),
                  const Gap(48),
                  SizedBox(
                    width: double.infinity,
                    child: CustomButton(
                      onPressed: () {
                        final start = startDateText.text.isNotEmpty
                            ? DateTime.tryParse(startDateText.text)
                            : null;
                        final end = endDateText.text.isNotEmpty
                            ? DateTime.tryParse(endDateText.text)
                            : null;

                        // バリデーション
                        final now = DateTime.now();
                        final today = DateTime(now.year, now.month, now.day);

                        // 開始日が現在より未来の場合
                        if (start != null && start.isAfter(today)) {
                          context.showErrorSnackBar(
                            context.l10n
                                .session_filter_page__start_date_future_error,
                          );
                          return;
                        }

                        // 終了日が開始日より過去の場合
                        if (start != null &&
                            end != null &&
                            end.isBefore(start)) {
                          context.showErrorSnackBar(
                            context.l10n
                                .session_filter_page__end_date_before_start_error,
                          );
                          return;
                        }

                        ref.read(
                            sessionFilterParametersNotifierProvider.notifier)
                          ..updateKeyword(keywordText.text.isNotEmpty
                              ? keywordText.text
                              : null)
                          ..updateDateRange(
                              start,
                              end?.add(const Duration(
                                  hours: 23, minutes: 59, seconds: 59)))
                          ..updatePlayer(tempPlayer.value)
                          ..updateLocation(tempLocation.value);
                        Navigator.of(context).pop();
                      },
                      child: Text(
                          context.l10n.session_filter_page__apply_button_label),
                    ),
                  ),
                  const Gap(16),
                  SizedBox(
                    width: double.infinity,
                    child: CustomButton(
                      variant: CustomButtonVariant.secondary,
                      onPressed: () {
                        keywordController.clear();
                        startDateController.clear();
                        endDateController.clear();
                        tempPlayer.value = null;
                        tempLocation.value = null;
                        ref.read(
                            sessionFilterParametersNotifierProvider.notifier)
                          ..updateKeyword(null)
                          ..updateDateRange(null, null)
                          ..updatePlayer(null)
                          ..updateLocation(null);
                      },
                      child: Text(
                          context.l10n.session_filter_page__reset_button_label),
                    ),
                  ),
                ],
              ),
            ),
          ),
        ),
      ),
    );
  }
}

