import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/controllers/session_list_controller.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/dark_mode_ext.dart';
import 'package:baseball_detector_flutter/views/routers/home_router.dart';
import 'package:baseball_detector_flutter/views/themes/color_manager.dart';

class SessionSearchBarWithFilter extends HookConsumerWidget {
  final String word;
  final ValueChanged<String> onSubmitted;
  const SessionSearchBarWithFilter(
      {super.key, required this.word, required this.onSubmitted});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final controller = useTextEditingController(text: word);
    final focusNode = useFocusNode();

    // フィルターパラメータ全体を取得
    final filterParams = ref.watch(sessionFilterParametersNotifierProvider);
    // 有効なフィルター数を計算
    int activeFilterCount = 0;
    if (filterParams.player != null) activeFilterCount++;
    if (filterParams.startDate != null) activeFilterCount++;
    if (filterParams.endDate != null) activeFilterCount++;
    if (filterParams.location != null && filterParams.location!.isNotEmpty) {
      activeFilterCount++;
    }

    useEffect(() {
      if (controller.text != word) controller.text = word;
      return null;
    }, [word]);

    void openFilterSheet() {
      Navigator.of(context).pushNamed(HomeRouter.sessionFilterPage);
    }

    return Row(
      children: [
        Expanded(
          child: TextField(
            controller: controller,
            focusNode: focusNode,
            decoration: InputDecoration(
              prefixIcon: Icon(Icons.search),
              hintText: context.l10n.session_search_bar_with_filter__hint,
              isDense: true,
              border:
                  OutlineInputBorder(borderRadius: BorderRadius.circular(12)),
              suffixIcon: controller.text.isNotEmpty
                  ? IconButton(
                      icon: Icon(Icons.clear),
                      onPressed: () {
                        controller.clear();
                        onSubmitted('');
                      },
                    )
                  : null,
            ),
            onSubmitted: onSubmitted,
            textInputAction: TextInputAction.search,
          ),
        ),
        const Gap(8),
        Material(
          color: Colors.transparent,
          child: InkWell(
            borderRadius: BorderRadius.circular(12),
            onTap: openFilterSheet,
            child: Container(
              padding: const EdgeInsets.all(12),
              decoration: BoxDecoration(
                color: context.isDarkMode
                    ? ColorManager.darkSurface
                    : ColorManager.lightSurface,
                borderRadius: BorderRadius.circular(12),
              ),
              child: Badge.count(
                count: activeFilterCount,
                isLabelVisible: activeFilterCount > 0,
                child: Icon(
                  Icons.tune,
                  color: context.isDarkMode
                      ? ColorManager.darkNavigationSelected
                      : ColorManager.lightNavigationSelected,
                ),
              ),
            ),
          ),
        ),
      ],
    );
  }
}

